  for (const [x, y] of cells) {               // loop(5) + bindings x,y(2)
    for (let dx = -1; dx <= 1; dx++) {         // loop(5) + binding dx(1) + const -1,1(2) + assign dx++(6)
      for (let dy = -1; dy <= 1; dy++) {       // loop(5) + binding dy(1) + const -1,1(2) + assign dy++(6)
        if (dx === 0 && dy === 0) continue;    // cond(4) + const 0,0(2)
        const candidate: Cell = [x+dx, y+dy];  // binding(1) + invocation +,+(4) + bindings(4)
        const isAlive = cells.some(...);       // binding(1)+invoke some(2)+invoke ===,===(4)+bindings(4)+...
        const alreadyAdded = candidates.some(..); // binding(1)+invoke some(2)+invoke===,===(4)+bindings(4)
        if (!isAlive && !alreadyAdded) candidates.push(candidate); // cond(4)+invoke push(2)+bindings(2)
